sql:
SELECT sector, AVG(investment_2015_2019) AS average_investment_2015_2019
FROM investment_data
GROUP BY sector;

SELECT COUNT(*) AS country_count
FROM countries
WHERE region = 'Europe';

SELECT AVG(predicted_value) AS average_predicted_value, predicted_value
FROM predictions
WHERE confidence_level > 0.8;

SELECT continent, COUNT(country_id) AS number_of_countries
FROM countries
GROUP BY continent;

